        type: "code",
        content: "// Базовая версия\nfunction insertionSort(arr) {\n  const n = arr.length;\n  for (let i = 1; i < n; i++) {\n    const key = arr[i];\n    let j = i - 1;\n    while (j >= 0 && arr[j] > key) {\n      arr[j + 1] = arr[j];\n      j--;\n    }\n    arr[j + 1] = key;\n  }\n  return arr;\n}\n\n// Сортировка по убыванию\nfunction insertionSortDesc(arr) {\n  const n = arr.length;\n  for (let i = 1; i < n; i++) {\n    const key = arr[i];\n    let j = i - 1;\n    while (j >= 0 && arr[j] < key) { // меняем знак\n      arr[j + 1] = arr[j];\n      j--;\n    }\n    arr[j + 1] = key;\n  }\n  return arr;\n}\n\n// Использование for вместо while\nfunction insertionSortFor(arr) {\n  for (let i = 1; i < arr.length; i++) {\n    const key = arr[i];\n    let j;\n    for (j = i - 1; j >= 0 && arr[j] > key; j--) {\n      arr[j + 1] = arr[j];\n    }\n    arr[j + 1] = key;\n  }\n  return arr;\n}",
