        content: "ВРЕМЕННАЯ СЛОЖНОСТЬ ОПЕРАЦИЙ:\n• enqueue: O(1) — добавление в конец.\n• dequeue: O(1) — удаление из начала.\n• front: O(1) — чтение первого элемента.\n• isEmpty: O(1) — проверка пустоты.\n\nПРОСТРАНСТВЕННАЯ СЛОЖНОСТЬ:\n• O(n) — хранит n элементов.\n\nРЕАЛИЗАЦИЯ (кольцевой буфер):\nclass CircularQueue {\n  constructor(capacity) {\n    this.buffer = new Array(capacity);\n    this.head = 0;\n    this.tail = 0;\n    this.size = 0;\n    this.capacity = capacity;\n  }\n  enqueue(x) {\n    if (this.size === this.capacity) return false;\n    this.buffer[this.tail] = x;\n    this.tail = (this.tail + 1) % this.capacity;\n    this.size++;\n    return true;\n  }\n  dequeue() {\n    if (this.size === 0) return null;\n    const val = this.buffer[this.head];\n    this.head = (this.head + 1) % this.capacity;\n    this.size--;\n    return val;\n  }\n}\n\nLinked List Queue:\nclass Node { constructor(v) { this.val = v; this.next = null; } }\nclass Queue {\n  constructor() { this.front = null; this.rear = null; this.size = 0; }\n  enqueue(x) {\n    const n = new Node(x);\n    if (this.rear) this.rear.next = n;\n    else this.front = n;\n    this.rear = n;\n    this.size++;\n  }\n  dequeue() {\n    if (!this.front) return null;\n    const v = this.front.val;\n    this.front = this.front.next;\n    if (!this.front) this.rear = null;\n    this.size--;\n    return v;\n  }\n}",
