  for (const [slug, blocks] of Object.entries(theoryTemplates)) {
    const algorithmId = algorithms.get(slug);
    if (!algorithmId) continue;

    // Idempotent: clear existing blocks for this algorithm so re-seeding does not
    // duplicate theory materials (tasks reference material_id with onDelete: SetNull).
    await prisma.theoryMaterial.deleteMany({ where: { algorithm_id: algorithmId } });

    for (let i = 0; i < blocks.length; i++) {
      const block = blocks[i];
      await prisma.theoryMaterial.create({
        data: {
          algorithm_id: algorithmId,
          title: block.title,
          content: block.content,
          type: block.type,
          quiz: block.quiz as any,
          order_num: i + 1,
        },
      });
    }
    console.log(`  ✓ ${slug}: ${blocks.length} blocks`);
  }

