      correct_answer: `class Node { constructor(val) { this.val = val; this.next = null; } }
class Queue {
  constructor() { this.head = null; this.tail = null; this._size = 0; }
  enqueue(x) {
    const n = new Node(x);
    if (this.tail) this.tail.next = n;
    else this.head = n;
    this.tail = n;
    this._size++;
  }
  dequeue() {
    if (!this.head) return null;
    const v = this.head.val;
    this.head = this.head.next;
    if (!this.head) this.tail = null;
    this._size--;
    return v;
  }
  front() { return this.head?.val ?? null; }
  isEmpty() { return this._size === 0; }
}`,
